-- collector-child shared dev baseline
ON DUPLICATE KEY UPDATE
    model_name = VALUES(model_name),
    data_type = VALUES(data_type),
    specs_json = VALUES(specs_json),
    sort_no = VALUES(sort_no),
    required_flag = VALUES(required_flag),
    description = VALUES(description),
    update_time = NOW(),
    deleted = 0;

UPDATE iot_product
SET metadata_json = JSON_SET(COALESCE(metadata_json, JSON_OBJECT()), '$.objectInsight', JSON_OBJECT('customMetrics', JSON_ARRAY(JSON_OBJECT('identifier', 'temp', 'displayName', '??', 'enabled', TRUE, 'includeInTrend', TRUE, 'includeInExtension', TRUE, 'sortNo', 10), JSON_OBJECT('identifier', 'humidity', 'displayName', '??', 'enabled', TRUE, 'includeInTrend', TRUE, 'includeInExtension', TRUE, 'sortNo', 20), JSON_OBJECT('identifier', 'signal_4g', 'displayName', '4G????', 'enabled', TRUE, 'includeInTrend', FALSE, 'includeInExtension', TRUE, 'sortNo', 30)))),
    update_by = 1,
    update_time = NOW(),
    deleted = 0
WHERE tenant_id = 1 AND product_key = 'nf-collect-rtu-v1' AND deleted = 0;

UPDATE iot_product
SET metadata_json = JSON_SET(COALESCE(metadata_json, JSON_OBJECT()), '$.objectInsight', JSON_OBJECT('customMetrics', JSON_ARRAY(JSON_OBJECT('identifier', 'value', 'displayName', '?????', 'enabled', TRUE, 'includeInTrend', TRUE, 'includeInExtension', TRUE, 'sortNo', 10), JSON_OBJECT('identifier', 'sensor_state', 'displayName', '?????', 'enabled', TRUE, 'includeInTrend', TRUE, 'includeInExtension', TRUE, 'sortNo', 20)))),
    update_by = 1,
    update_time = NOW(),
    deleted = 0
WHERE tenant_id = 1 AND product_key = 'nf-monitor-laser-rangefinder-v1' AND deleted = 0;

UPDATE iot_product
SET metadata_json = JSON_SET(COALESCE(metadata_json, JSON_OBJECT()), '$.objectInsight', JSON_OBJECT('customMetrics', JSON_ARRAY(JSON_OBJECT('identifier', 'dispsX', 'displayName', '??????????', 'enabled', TRUE, 'includeInTrend', TRUE, 'includeInExtension', TRUE, 'sortNo', 10), JSON_OBJECT('identifier', 'dispsY', 'displayName', '???????????', 'enabled', TRUE, 'includeInTrend', TRUE, 'includeInExtension', TRUE, 'sortNo', 20), JSON_OBJECT('identifier', 'sensor_state', 'displayName', '?????', 'enabled', TRUE, 'includeInTrend', TRUE, 'includeInExtension', TRUE, 'sortNo', 30)))),
    update_by = 1,
    update_time = NOW(),
    deleted = 0
WHERE tenant_id = 1 AND product_key = 'nf-monitor-deep-displacement-v1' AND deleted = 0;

ON DUPLICATE KEY UPDATE
    org_id = VALUES(org_id),
    org_name = VALUES(org_name),
    product_id = VALUES(product_id),
    device_name = VALUES(device_name),
    protocol_code = VALUES(protocol_code),
    online_status = VALUES(online_status),
    activate_status = VALUES(activate_status),
    device_status = VALUES(device_status),
    firmware_version = VALUES(firmware_version),
    ip_address = VALUES(ip_address),
    last_online_time = VALUES(last_online_time),
    last_report_time = VALUES(last_report_time),
    longitude = VALUES(longitude),
    latitude = VALUES(latitude),
    address = VALUES(address),
    metadata_json = VALUES(metadata_json),
    remark = VALUES(remark),
    update_by = 1,
    update_time = NOW(),
    deleted = 0;

ON DUPLICATE KEY UPDATE
    parent_device_id = VALUES(parent_device_id),
    parent_device_code = VALUES(parent_device_code),
    child_device_id = VALUES(child_device_id),
    child_device_code = VALUES(child_device_code),
    child_product_id = VALUES(child_product_id),
    child_product_key = VALUES(child_product_key),
    relation_type = VALUES(relation_type),
    canonicalization_strategy = VALUES(canonicalization_strategy),
    status_mirror_strategy = VALUES(status_mirror_strategy),
    enabled = VALUES(enabled),
    remark = VALUES(remark),
    update_by = 1,
    update_time = NOW(),
    deleted = 0;

ON DUPLICATE KEY UPDATE
    property_name = VALUES(property_name),
    property_value = VALUES(property_value),
    value_type = VALUES(value_type),
    report_time = VALUES(report_time),
    update_time = NOW();
